import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Cloudflare R2 Channel شامل کریں","description":"","frontmatter":{},"headers":[],"relativePath":"ur/upload/cloudflare-r2.md","filePath":"ur/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"ur/upload/cloudflare-r2.md"};function c(u,e,s,h,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-r2-channel-شامل-کریں" tabindex="-1">Cloudflare R2 Channel شامل کریں <a class="header-anchor" href="#cloudflare-r2-channel-شامل-کریں" aria-label="Permalink to &quot;Cloudflare R2 Channel شامل کریں&quot;">​</a></h1><h2 id="کب-استعمال-کریں" tabindex="-1">کب استعمال کریں <a class="header-anchor" href="#کب-استعمال-کریں" aria-label="Permalink to &quot;کب استعمال کریں&quot;">​</a></h2><p>Cloudflare R2 اس وقت مناسب ہے جب:</p><ul><li>آپ کی ImgBed site پہلے ہی Cloudflare پر deployed ہے اور آپ اسی Cloudflare account کے R2 bucket میں files رکھنا چاہتے ہیں۔</li><li>آپ الگ S3 endpoint، access key، اور secret key configure نہیں کرنا چاہتے۔</li><li>آپ چاہتے ہیں کہ reads اور writes کم setup کے ساتھ Worker یا Pages R2 binding کے ذریعے چلیں۔</li></ul><p>مختصر بات:</p><p>R2 channel ImgBed admin panel کے اندر manual طور پر نہیں بنایا جاتا۔ پہلے Cloudflare project کے ساتھ R2 bucket bind کریں، اور binding variable name لازماً <code>img_r2</code> ہونا چاہیے۔</p><h2 id="شروع-کرنے-سے-پہلے-کیا-چاہیے" tabindex="-1">شروع کرنے سے پہلے کیا چاہیے <a class="header-anchor" href="#شروع-کرنے-سے-پہلے-کیا-چاہیے" aria-label="Permalink to &quot;شروع کرنے سے پہلے کیا چاہیے&quot;">​</a></h2><ul><li>Cloudflare account۔</li><li>پہلے سے موجود R2 bucket۔</li><li>اس Cloudflare project کو manage کرنے کی permission جہاں ImgBed deployed ہے۔</li></ul><h2 id="cloudflare-میں-configure-کریں" tabindex="-1">Cloudflare میں Configure کریں <a class="header-anchor" href="#cloudflare-میں-configure-کریں" aria-label="Permalink to &quot;Cloudflare میں Configure کریں&quot;">​</a></h2><h3 id="_1-r2-bucket-بنائیں" tabindex="-1">1. R2 Bucket بنائیں <a class="header-anchor" href="#_1-r2-bucket-بنائیں" aria-label="Permalink to &quot;1. R2 Bucket بنائیں&quot;">​</a></h3><ol><li>Cloudflare Dashboard میں log in کریں۔</li><li><code>R2 Object Storage</code> کھولیں۔</li><li>Create bucket پر کلک کریں۔</li><li>bucket name منتخب کریں، مثلاً <code>imgbed</code>۔</li></ol><p>uploaded files اسی bucket میں محفوظ ہوں گی۔</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bucket-کو-imgbed-project-سے-bind-کریں" tabindex="-1">2. Bucket کو ImgBed Project سے Bind کریں <a class="header-anchor" href="#_2-bucket-کو-imgbed-project-سے-bind-کریں" aria-label="Permalink to &quot;2. Bucket کو ImgBed Project سے Bind کریں&quot;">​</a></h3><p>اپنی deployment type کے مطابق binding location منتخب کریں:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>binding add کرتے وقت اہم fields یہ ہیں:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>جو bucket آپ نے بنایا ہے اسے منتخب کریں۔</td></tr></tbody></table><p>Variable name بالکل <code>img_r2</code> ہونا چاہیے۔ R2 files کا upload، read، اور delete سب اسی binding name پر depend کرتا ہے۔</p><h3 id="_3-project-دوبارہ-deploy-کریں" tabindex="-1">3. Project دوبارہ Deploy کریں <a class="header-anchor" href="#_3-project-دوبارہ-deploy-کریں" aria-label="Permalink to &quot;3. Project دوبارہ Deploy کریں&quot;">​</a></h3><p>binding save کرنے کے بعد ImgBed کو redeploy کریں تاکہ Worker یا Pages runtime <code>img_r2</code> تک access حاصل کر سکے۔</p><h2 id="imgbed-میں-کیا-نظر-آئے-گا" tabindex="-1">ImgBed میں کیا نظر آئے گا <a class="header-anchor" href="#imgbed-میں-کیا-نظر-آئے-گا" aria-label="Permalink to &quot;ImgBed میں کیا نظر آئے گا&quot;">​</a></h2><p>R2 binding دستیاب ہونے کے بعد کھولیں:</p><ol><li>System Settings۔</li><li>Upload Settings۔</li><li><code>Cloudflare R2</code> channel۔</li></ol><p>system خود ایک fixed channel بناتا ہے:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>یہ fixed binding channel ہے۔ اسے بنانے کے لیے Add Channel پر کلک کرنے کی ضرورت نہیں، اور اسے عام channel کی طرح delete بھی نہیں کیا جا سکتا۔</p><h2 id="admin-panel-میں-editable-fields" tabindex="-1">Admin Panel میں Editable Fields <a class="header-anchor" href="#admin-panel-میں-editable-fields" aria-label="Permalink to &quot;Admin Panel میں Editable Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>کام</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>یہ کنٹرول کرتا ہے کہ R2 upload selection میں شامل ہو یا نہیں۔</td><td>Yes</td></tr><tr><td>Account ID</td><td>صرف اس وقت استعمال ہوتا ہے جب quota limits enabled ہوں اور official R2 usage query کرنا ہو۔</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Bucket name</td><td>صرف اس وقت استعمال ہوتا ہے جب quota limits enabled ہوں اور official R2 usage query کرنا ہو۔</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Quota limit</td><td>یہ کنٹرول کرتا ہے کہ capacity کی بنیاد پر R2 channel upload selection میں شامل ہو یا نہیں۔</td><td>No</td></tr><tr><td>Threshold</td><td>usage مخصوص percentage تک پہنچنے کے بعد اس channel پر لکھنا روک دیتا ہے۔</td><td>Required when quota limits are enabled</td></tr></tbody></table><p>Account ID Cloudflare dashboard کے account information panel سے copy کیا جا سکتا ہے۔ اسے صرف اس وقت بھریں جب آپ چاہتے ہوں کہ ImgBed R2 quota usage query اور enforce کرے۔</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Cloudflare میں R2 bucket بنائیں۔</li><li>ImgBed project کی Cloudflare settings کھولیں۔</li><li>R2 bucket binding add کریں۔</li><li><code>Variable name</code> کو <code>img_r2</code> رکھیں۔</li><li>بنایا ہوا R2 bucket منتخب کریں۔</li><li>binding save کریں اور ImgBed redeploy کریں۔</li><li>واپس ImgBed -&gt; System Settings -&gt; Upload Settings میں جائیں۔</li><li>confirm کریں کہ <code>Cloudflare R2</code> channel نظر آ رہا ہے اور enabled ہے۔</li></ol><p>اگر آپ چاہتے ہیں کہ R2 capacity کی بنیاد پر upload selection میں حصہ لے، quota limit enable کریں، پھر Account ID، bucket name، quota limit، اور threshold درج کر کے save کریں۔</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="verify-کیسے-کریں" tabindex="-1">Verify کیسے کریں <a class="header-anchor" href="#verify-کیسے-کریں" aria-label="Permalink to &quot;Verify کیسے کریں&quot;">​</a></h2><ul><li>fixed <code>Cloudflare R2</code> channel Upload Settings میں دکھائی دے۔</li><li>channel card پر enabled status دکھے۔</li><li>چھوٹی test file کامیابی سے upload ہو اور returned link عام طور پر کھل جائے۔</li><li>اگر file کھولنے پر <code>R2 database binding is not configured</code> آئے، runtime کو <code>img_r2</code> binding نہیں ملی۔ Cloudflare میں binding name چیک کریں اور project redeploy کریں۔</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
